import React, { useState } from "react";
import axios from "axios";
import "./App.css";

function App() {
  const [file, setFile] = useState(null);
  const [preview, setPreview] = useState(null);
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);

  const handleFileChange = (e) => {
    const f = e.target.files[0];
    setFile(f);
    setPreview(URL.createObjectURL(f));
  };

  const handlePredict = async () => {
    if (!file) return alert("Upload image first");

    const formData = new FormData();
    formData.append("file", file);

    setLoading(true);

    try {
      const res = await axios.post(
        "http://localhost:5000/predict",
        formData,
        { timeout: 60000 }
      );
      setResult(res.data);
    } catch (err) {
      console.error(err);
      alert("Prediction failed");
    }

    setLoading(false);
  };

  return (
    <div className="app">
      <h1 className="title">🍇 Grape Disease Detection</h1>

      <div className="main-card">
        <input type="file" onChange={handleFileChange} className="file-input" />

        {preview && (
          <img src={preview} alt="preview" className="preview-img" />
        )}

        <button className="predict-btn" onClick={handlePredict}>
          {loading ? "Analyzing..." : "Predict"}
        </button>

        {loading && <p className="loading">Running AI models... ⏳</p>}
      </div>

      {result && (
        <div className="result-card">
          <h2>Final Prediction</h2>
          <h1 className="final-result">{result.final_prediction}</h1>

          <p className="confidence">
            Confidence: {(result.final_confidence * 100).toFixed(2)}%
          </p>

          <p className="best-model">
            Best Model: <b>{result.best_model}</b>
          </p>

          <div className="models-grid">
            {Object.entries(result.models).map(([name, data]) => (
              <div
                key={name}
                className={
                  name === result.best_model
                    ? "model-card best"
                    : "model-card"
                }
              >
                <h3>{name.toUpperCase()}</h3>
                <p>{data.prediction}</p>
                <p>{(data.confidence * 100).toFixed(2)}%</p>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}

export default App;
